from typing import Dict, List, Union, Any

def calculateStatistics(scores_json: str) -> Dict[str, Any]:
    try:
        # Parse JSON data
        data = json.loads(scores_json)

        # Extract scores, ensuring they are numbers
        scores = []
        if isinstance(data, list):
            # If JSON is already a list of scores
            scores = [float(score) for score in data if isinstance(score, (int, float)) or 
                     (isinstance(score, str) and score.replace('.', '', 1).isdigit())]
        elif isinstance(data, dict):
            # If JSON is a dictionary containing scores
            for value in data.values():
                if isinstance(value, (int, float)):
                    scores.append(float(value))
                elif isinstance(value, str) and value.replace('.', '', 1).isdigit():
                    scores.append(float(value))
                elif isinstance(value, dict) and 'score' in value:
                    if isinstance(value['score'], (int, float)):
                        scores.append(float(value['score']))
                    elif isinstance(value['score'], str) and value['score'].replace('.', '', 1).isdigit():
                        scores.append(float(value['score']))

        if not scores:
            return {"error": "No valid numeric scores found in the input data"}

        # Calculate statistics
        mean = statistics.mean(scores)
        median = statistics.median(scores)

        # Calculate mode (might have multiple modes)
        try:
            mode = statistics.mode(scores)
        except statistics.StatisticsError:
            # If there are multiple modes, find them manually
            frequency = {}
            for score in scores:
                frequency[score] = frequency.get(score, 0) + 1
            max_freq = max(frequency.values())
            mode = [score for score, freq in frequency.items() if freq == max_freq]

        return {
            "mean": mean,
            "median": median,
            "mode": mode,
            "count": len(scores),
            "valid_scores_processed": len(scores)
        }

    except json.JSONDecodeError:
        return {"error": "Invalid JSON format"}
    except Exception as e:
        return {"error": f"An error occurred: {str(e)}"}
