public class TrafficOptimizer {
    public static Map<String, List<String>> trafficOptimizer(
            Graph<String> cityGraph,
            Map<Edge<String>, Double> trafficDensity) {

        Map<String, List<String>> optimizedPaths = new HashMap<>();
        Set<String> allVertices = cityGraph.getAllVertices();

        for (String source : allVertices) {
            Map<String, Double> distances = new HashMap<>();
            Map<String, String> predecessors = new HashMap<>();
            PriorityQueue<Node> queue = new PriorityQueue<>(Comparator.comparingDouble(n -> n.distance));

            // Initialize distances
            for (String vertex : allVertices) {
                distances.put(vertex, Double.POSITIVE_INFINITY);
                predecessors.put(vertex, null);
            }
            distances.put(source, 0.0);
            queue.add(new Node(source, 0.0));

            // Dijkstra's algorithm with traffic density as weight
            while (!queue.isEmpty()) {
                Node current = queue.poll();
                String currentVertex = current.vertex;
                double currentDistance = current.distance;

                if (currentDistance > distances.get(currentVertex)) {
                    continue;
                }

                for (String neighbor : cityGraph.getNeighbors(currentVertex)) {
                    Edge<String> edge = new Edge<>(currentVertex, neighbor);
                    double trafficFactor = trafficDensity.getOrDefault(edge, 1.0);
                    double edgeWeight = cityGraph.getEdgeWeight(currentVertex, neighbor) * trafficFactor;
                    double newDistance = distances.get(currentVertex) + edgeWeight;

                    if (newDistance < distances.get(neighbor)) {
                        distances.put(neighbor, newDistance);
                        predecessors.put(neighbor, currentVertex);
                        queue.add(new Node(neighbor, newDistance));
                    }
                }
            }

            // Construct optimized paths from source to all destinations
            for (String destination : allVertices) {
                if (!destination.equals(source)) {
                    List<String> path = constructPath(source, destination, predecessors);
                    if (!path.isEmpty()) {
                        optimizedPaths.put(source + "->" + destination, path);
                    }
                }
            }
        }

        return optimizedPaths;
    }

    private static List<String> constructPath(String source, String destination, Map<String, String> predecessors) {
        List<String> path = new ArrayList<>();
        String current = destination;

        // If destination is unreachable
        if (predecessors.get(current) == null) {
            return path;
        }

        while (!current.equals(source)) {
            path.add(current);
            current = predecessors.get(current);
        }
        path.add(source);
        Collections.reverse(path);

        return path;
    }

    private static class Node {
        String vertex;
        double distance;

        public Node(String vertex, double distance) {
            this.vertex = vertex;
            this.distance = distance;
        }
    }

    private static class Edge<T> {
        T source;
        T destination;

        public Edge(T source, T destination) {
            this.source = source;
            this.destination = destination;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Edge<?> edge = (Edge<?>) o;
            return Objects.equals(source, edge.source) && Objects.equals(destination, edge.destination);
        }

        @Override
        public int hashCode() {
            return Objects.hash(source, destination);
        }
    }

    // Example Graph interface
    public interface Graph<T> {
        Set<T> getAllVertices();
        List<T> getNeighbors(T vertex);
        double getEdgeWeight(T source, T destination);
    }
}
