    Response response;
    response.requestID = request.requestID;

    // Validate endpoint
    if (request.endpoint.empty() || request.endpoint[0] != '/') {
        response.statusCode = 400; // Bad Request
        response.data = "Invalid endpoint format";
        return response;
    }

    // Process based on endpoint
    if (request.endpoint == "/api/data") {
        if (request.payload.empty()) {
            response.statusCode = 400;
            response.data = "Empty payload";
        } else {
            response.statusCode = 200; // OK
            response.data = "Processed payload: " + request.payload;
        }
    } else if (request.endpoint == "/api/status") {
        response.statusCode = 200;
        response.data = "Server status: Online";
    } else {
        response.statusCode = 404; // Not Found
        response.data = "Endpoint not found";
    }

    return response;
