fn calculate_stats(numbers: &[i32]) -> Option<(i32, i32, f64)> {
    if numbers.is_empty() {
        return None;
    }

    let mut min = numbers[0];
    let mut max = numbers[0];
    let mut sum: i64 = 0;

    for &num in numbers {
        min = min.min(num);
        max = max.max(num);
        sum += num as i64;
    }

