public List<Integer> analyzeNetworkConnectivity(List<List<Integer>> graph) {
    List<Integer> criticalNodes = new ArrayList<>();
    int n = graph.size();
    int[] disc = new int[n];
    int[] low = new int[n];
    boolean[] visited = new boolean[n];
    int[] parent = new int[n];
    Arrays.fill(parent, -1);

    int time = 0;

    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            dfs(i, visited, disc, low, parent, graph, criticalNodes, time);
        }
    }

    return criticalNodes;
}

private void dfs(int u, boolean[] visited, int[] disc, int[] low, int[] parent, 
                List<List<Integer>> graph, List<Integer> criticalNodes, int time) {
    visited[u] = true;
    disc[u] = low[u] = ++time;
    int children = 0;
    boolean isArticulationPoint = false;

    for (int v : graph.get(u)) {
        if (!visited[v]) {
            children++;
            parent[v] = u;

            dfs(v, visited, disc, low, parent, graph, criticalNodes, time);

            low[u] = Math.min(low[u], low[v]);

            if (parent[u] != -1 && low[v] >= disc[u]) {
                isArticulationPoint = true;
            }

            if (parent[u] == -1 && children > 1) {
                isArticulationPoint = true;
            }
        } else if (v != parent[u]) {
            low[u] = Math.min(low[u], disc[v]);
        }
    }

    if (isArticulationPoint) {
        criticalNodes.add(u);
    }
}
