    id: String,
    terminal: String,
    is_occupied: bool,
    aircraft_id: Option<String>,
}

enum ActionType {
    Allocate,
    Deallocate,
    Status,
}

struct GateAction {
    action_type: ActionType,
    gate_id: String,
    terminal: String,
    aircraft_id: Option<String>,
}

struct GateResponse {
    success: bool,
    message: String,
    gate: Option<Gate>,
}

fn manageAirportGates(gates: &mut Vec<Gate>, action: GateAction) -> GateResponse {
    match action.action_type {
        ActionType::Allocate => {
            // Find the gate
            for gate in gates.iter_mut() {
                if gate.id == action.gate_id && gate.terminal == action.terminal {
                    if gate.is_occupied {
                        return GateResponse {
                            success: false,
                            message: format!("Gate {} in terminal {} is already occupied", gate.id, gate.terminal),
                            gate: None,
                        };
                    }

                    // Allocate the gate
                    gate.is_occupied = true;
                    gate.aircraft_id = action.aircraft_id;

                    return GateResponse {
                        success: true,
                        message: format!("Gate {} in terminal {} has been allocated", gate.id, gate.terminal),
                        gate: Some(gate.clone()),
                    };
                }
            }

            return GateResponse {
                success: false,
                message: format!("Gate {} in terminal {} not found", action.gate_id, action.terminal),
                gate: None,
            };
        },
        ActionType::Deallocate => {
            // Find the gate
            for gate in gates.iter_mut() {
                if gate.id == action.gate_id && gate.terminal == action.terminal {
                    if !gate.is_occupied {
                        return GateResponse {
                            success: false,
                            message: format!("Gate {} in terminal {} is not occupied", gate.id, gate.terminal),
                            gate: None,
                        };
                    }

                    // Deallocate the gate
                    gate.is_occupied = false;
                    gate.aircraft_id = None;

                    return GateResponse {
                        success: true,
                        message: format!("Gate {} in terminal {} has been deallocated", gate.id, gate.terminal),
                        gate: Some(gate.clone()),
                    };
                }
            }

            return GateResponse {
                success: false,
                message: format!("Gate {} in terminal {} not found", action.gate_id, action.terminal),
                gate: None,
            };
        },
        ActionType::Status => {
            // Find the gate and report status
            for gate in gates.iter() {
                if gate.id == action.gate_id && gate.terminal == action.terminal {
                    let status = if gate.is_occupied { "occupied" } else { "available" };

                    return GateResponse {
                        success: true,
                        message: format!("Gate {} in terminal {} is {}", gate.id, gate.terminal, status),
                        gate: Some(gate.clone()),
                    };
                }
            }

            return GateResponse {
                success: false,
                message: format!("Gate {} in terminal {} not found", action.gate_id, action.terminal),
                gate: None,
            };
        },
    }
}
