                }
            }

            if (!found) {
                auto newNode = std::make_shared<PermissionNode>(path[i], granted && (i == path.size() - 1));
                currentNode->children.push_back(newNode);
                currentNode = newNode;
            }
        }

        // Update the permission for the final node
        if (!path.empty()) {
            currentNode->granted = granted;
        }
    }

    bool updatePermission(const std::vector<std::string>& path, bool granted) {
        auto node = findNode(path);
        if (node) {
            node->granted = granted;
            return true;
        }
        return false;
    }

    bool removePermission(const std::vector<std::string>& path) {
        if (path.empty()) return false;

        auto currentNode = root;
        std::shared_ptr<PermissionNode> parentNode = nullptr;

        for (size_t i = 0; i < path.size() - 1; ++i) {
            bool found = false;
            for (auto& child : currentNode->children) {
                if (child->name == path[i]) {
                    parentNode = currentNode;
                    currentNode = child;
                    found = true;
                    break;
                }
            }

            if (!found) return false;
        }

        // Find and remove the target node
        for (auto it = currentNode->children.begin(); it != currentNode->children.end(); ++it) {
            if ((*it)->name == path.back()) {
                currentNode->children.erase(it);
                return true;
            }
        }

        return false;
    }

    std::shared_ptr<PermissionNode> findNode(const std::vector<std::string>& path) {
        auto currentNode = root;

        for (const auto& segment : path) {
            bool found = false;
            for (auto& child : currentNode->children) {
                if (child->name == segment) {
                    currentNode = child;
                    found = true;
                    break;
                }
            }

            if (!found) return nullptr;
        }

        return currentNode;
    }
};

