fn rotate(matrix: &mut Vec<Vec<i32>>) {
    if matrix.is_empty() {
        return;
    }

    let n = matrix.len();
    // Transpose matrix
    for i in 0..n {
        for j in i+1..n {
            let temp = matrix[i][j];
            matrix[i][j] = matrix[j][i];
            matrix[j][i] = temp;
        }
    }

    // Reverse each row
    for row in matrix.iter_mut() {
        row.reverse();
    }
}

fn flip(matrix: &mut Vec<Vec<i32>>) {
    for row in matrix.iter_mut() {
        row.reverse();
    }
}

fn invert(matrix: &mut Vec<Vec<i32>>) {
    for row in matrix.iter_mut() {
        for cell in row.iter_mut() {
            *cell = 1 - *cell;
        }
    }
}
