import java.util.*;

public class FileSystemSimulator {

    static class Folder {
        String name;
        Folder parent;
        Map<String, Folder> subfolders;

        public Folder(String name, Folder parent) {
            this.name = name;
            this.parent = parent;
            this.subfolders = new HashMap<>();
        }

        public String getPath() {
            if (parent == null) {
                return "/" + name;
            }
            String parentPath = parent.getPath();
            if (parentPath.equals("/")) {
                return parentPath + name;
            }
            return parentPath + "/" + name;
        }
    }

    private Folder root;
    private Map<String, Folder> folderIndex;

    public FileSystemSimulator() {
        this.root = new Folder("", null);
        this.folderIndex = new HashMap<>();
    }

    public String fs_simulator(String jsonInput) {
        try {
            org.json.JSONObject json = new org.json.JSONObject(jsonInput);
            String action = json.getString("action");

            switch (action) {
                case "add":
                    String folderName = json.getString("folderName");
                    String parentName = json.getString("parentName");
                    return addFolder(folderName, parentName);

                case "move":
                    String sourceName = json.getString("folderName");
                    String targetName = json.getString("targetName");
                    return moveFolder(sourceName, targetName);

                case "remove":
                    String removeName = json.getString("folderName");
                    return removeFolder(removeName);

                case "path":
                    String pathName = json.getString("folderName");
                    return getPath(pathName);

                default:
                    return "Unknown action: " + action;
            }
        } catch (Exception e) {
            return "Error: " + e.getMessage();
        }
    }

    private String addFolder(String folderName, String parentName) {
        if (folderIndex.containsKey(folderName)) {
            return "Folder '" + folderName + "' already exists";
        }

        Folder parent;
        if (parentName.isEmpty() || parentName.equals("/")) {
            parent = root;
        } else if (!folderIndex.containsKey(parentName)) {
            return "Parent folder '" + parentName + "' not found";
        } else {
            parent = folderIndex.get(parentName);
        }

        Folder newFolder = new Folder(folderName, parent);
        parent.subfolders.put(folderName, newFolder);
        folderIndex.put(folderName, newFolder);

        return "Added folder '" + folderName + "' to '" + (parent == root ? "/" : parent.name) + "'";
    }

    private String moveFolder(String folderName, String targetName) {
        if (!folderIndex.containsKey(folderName)) {
            return "Folder '" + folderName + "' not found";
        }

        Folder target;
        if (targetName.isEmpty() || targetName.equals("/")) {
            target = root;
        } else if (!folderIndex.containsKey(targetName)) {
            return "Target folder '" + targetName + "' not found";
        } else {
            target = folderIndex.get(targetName);
        }

        Folder folder = folderIndex.get(folderName);

        // Check for circular dependency
        Folder current = target;
        while (current != null) {
            if (current == folder) {
                return "Cannot move a folder to its own subfolder";
            }
            current = current.parent;
        }

        // Remove from old parent
        folder.parent.subfolders.remove(folderName);

        // Add to new parent
        folder.parent = target;
        target.subfolders.put(folderName, folder);

        return "Moved folder '" + folderName + "' to '" + (target == root ? "/" : target.name) + "'";
    }

    private String removeFolder(String folderName) {
        if (!folderIndex.containsKey(folderName)) {
            return "Folder '" + folderName + "' not found";
        }

        Folder folder = folderIndex.get(folderName);

        // Remove from parent
        folder.parent.subfolders.remove(folderName);

        // Remove all subfolders from index
        Queue<Folder> queue = new LinkedList<>();
        queue.add(folder);

        while (!queue.isEmpty()) {
            Folder current = queue.poll();
            folderIndex.remove(current.name);

            for (Folder subfolder : current.subfolders.values()) {
                queue.add(subfolder);
            }
        }

        return "Removed folder '" + folderName + "' and all its subfolders";
    }

    private String getPath(String folderName) {
        if (!folderIndex.containsKey(folderName)) {
            return "Folder '" + folderName + "' not found";
        }

        Folder folder = folderIndex.get(folderName);
        return folder.getPath();
    }
}
