        if (phoneBook.find(name) != phoneBook.end()) {
            phoneBook.erase(name);
            result = "Contact deleted successfully";
        }
        else {
            result = "Contact not found";
        }
    }
    else if (command == "update") {
        std::string name = commandData.at("name");
        if (phoneBook.find(name) != phoneBook.end()) {
            if (commandData.find("phone") != commandData.end())
                phoneBook[name]["phone"] = commandData.at("phone");

            if (commandData.find("email") != commandData.end())
                phoneBook[name]["email"] = commandData.at("email");

            if (commandData.find("address") != commandData.end())
                phoneBook[name]["address"] = commandData.at("address");

            result = "Contact updated successfully";
        }
        else {
            result = "Contact not found";
        }
    }
    else if (command == "search") {
        std::string name = commandData.at("name");
        if (phoneBook.find(name) != phoneBook.end()) {
            result = "Contact found:\n";
            for (const auto& field : phoneBook[name]) {
                result += field.first + ": " + field.second + "\n";
            }
        }
        else {
            result = "Contact not found";
        }
    }
    else if (command == "list") {
        if (phoneBook.empty()) {
            result = "Phone book is empty";
        }
        else {
            result = "Contacts:\n";
            for (const auto& contact : phoneBook) {
                result += contact.first + " - " + contact.second.at("phone") + "\n";
            }
        }
    }
    else {
        result = "Invalid command";
    }

