def generateConfigTree(parameters):
    # Initialize configuration tree
    config_tree = {}

    # Process hostname if provided
    if 'hostname' in parameters:
        config_tree['hostname'] = parameters['hostname']

    # Process IP addresses
    if 'ip_addresses' in parameters:
        config_tree['ip_addresses'] = {}
        for interface, ip_data in parameters['ip_addresses'].items():
            config_tree['ip_addresses'][interface] = ip_data

    # Process routing protocols
    if 'routing_protocols' in parameters:
        config_tree['routing_protocols'] = {}
        for protocol, protocol_data in parameters['routing_protocols'].items():
            config_tree['routing_protocols'][protocol] = protocol_data

    # Process any other parameters
    for key, value in parameters.items():
        if key not in ['hostname', 'ip_addresses', 'routing_protocols']:
            config_tree[key] = value

    # Methods to modify configuration tree
    def get_config(keys=None):
        if keys is None:
            return config_tree

        current = config_tree
        if isinstance(keys, str):
            keys = [keys]

        for key in keys:
            if key in current:
                current = current[key]
            else:
                return None
        return current

    def set_config(keys, value):
        if isinstance(keys, str):
            keys = [keys]

        current = config_tree
        for key in keys[:-1]:
            if key not in current:
                current[key] = {}
            current = current[key]

        current[keys[-1]] = value
        return True

    def add_route(network, next_hop, metric=1):
        if 'static_routes' not in config_tree:
            config_tree['static_routes'] = []

        config_tree['static_routes'].append({
            'network': network,
            'next_hop': next_hop,
            'metric': metric
        })
        return True

    # Attach methods to the config_tree
    config_tree['get'] = get_config
    config_tree['set'] = set_config
    config_tree['add_route'] = add_route

    return config_tree
